import reflex as rx
# Check var type annotations supported
class TestState(rx.State):
    prices: dict[str, float] = {'AAPL': 150.0, 'GOOG': 2800.0}
    symbols: list[str] = ['AAPL', 'GOOG']

    @rx.var(cache=True)
    def percent_change(self) -> dict[str, float]:
        return {s: round((self.prices[s] - 150.0) / 150.0 * 100.0, 4) for s in self.prices}

    @rx.var(cache=True)
    def ticker_data(self) -> list[dict]:
        return [{'symbol': s, 'price': self.prices[s]} for s in self.symbols]

print('State defined successfully')
